export function SubmitButton({name, children}){
    // console.log(name)
    return (
        <p type="submitButton">{name + children}</p>
    )
}

export function OptionButton(props){
    return (
        <Button  type="optionButton">{props.children}</Button>
    )
}

function Button(props){
    let style = "btn " + props.type;
    return (
        <button className={style} onClick={() => {props.onQuizName(props.children)}}>{props.children}</button>
    )
}
